var event = $input.item.json;
var sub = event.data?.object || event;

var subscriptionId = sub.id;
var customerId = sub.customer;
var status = sub.status;
var currentPeriodStart = sub.current_period_start ? new Date(sub.current_period_start * 1000).toISOString() : null;
var currentPeriodEnd = sub.current_period_end ? new Date(sub.current_period_end * 1000).toISOString() : null;
var clientId = sub.metadata?.clientId;
var tenantId = sub.metadata?.tenantId;
var planName = sub.metadata?.planName || sub.items?.data?.[0]?.plan?.nickname || '';

if (!clientId || !tenantId) {
  throw new Error('Metadata manquantes dans subscription: clientId=' + (clientId || 'ABSENT') + ', tenantId=' + (tenantId || 'ABSENT'));
}

return [{
  json: {
    subscriptionId,
    customerId,
    status,
    currentPeriodStart,
    currentPeriodEnd,
    clientId,
    tenantId,
    planName
  }
}];

var data = $('02. Parser subscription').item.json;
var planName = (data.planName || 'Abonnement').replace(/'/g, "''");

return [{
  json: {
    query: "INSERT INTO notifications (id, tenant_id, titre, message, type, lu, created_at) VALUES (gen_random_uuid(), '" + data.tenantId.replace(/'/g, "''") + "', 'Abonnement Stripe cree', 'L''abonnement " + planName + " (" + data.subscriptionId + ") a ete cree sur Stripe et synchronise en base de donnees.', 'info', false, NOW())"
  }
}];

var data = $('02. Parser subscription').item.json;
// Récupérer le montant depuis l'abonnement Stripe
var raw = $('01. Stripe Trigger').first().json;
var sub = raw.data?.object || raw;
var amount = sub.items?.data?.[0]?.plan?.amount || sub.plan?.amount || 0;
var montantTtc = (amount / 100).toFixed(2);
var montantHt = (amount / 100 / 1.2).toFixed(2);

return [{
  json: {
    url: 'https://n8n.talosprimes.com/webhook/revenue_track',
    body: {
      tenantId: data.tenantId,
      data: {
        clientFinalId: data.clientId,
        type: 'abonnement',
        montantHt: parseFloat(montantHt),
        montantTtc: parseFloat(montantTtc),
        description: 'Abonnement Stripe - ' + (data.planName || 'Mensuel'),
        stripePaymentId: data.subscriptionId,
        mois: new Date().toISOString().slice(0, 7)
      }
    }
  }
}];
